<?php
require_once __DIR__.'/app/layout.php'; require_login();
$admin=is_admin();
if($admin){$rows=db()->query('SELECT * FROM employees ORDER BY active DESC,name')->fetchAll();}
else{$own=require_operator_employee_id();$st=db()->prepare('SELECT * FROM employees WHERE id=?');$st->execute([$own]);$rows=$st->fetchAll();}
page_header('Data Pegawai','employees');?><div class="card"><div class="section-title"><h2><?=$admin?'Daftar Pegawai':'Data Saya'?></h2><?php if($admin):?><a class="btn" href="employee_form.php">Tambah pegawai</a><?php endif;?></div><?php foreach($rows as $r):?><div class="employee-card"><div><h3><?=e($r['name'])?> <?php if(!$r['active']):?><span class="badge danger">Nonaktif</span><?php endif;?></h3><p>NIP <?=e($r['nip']?:'-')?> · Gol <?=e($r['grade']?:'-')?></p><p><?=e($r['position']?:'-')?></p><span class="badge <?=$r['signature_path']?'ok':'warn'?>">TTD <?=$r['signature_path']?'tersedia':'belum ada'?></span></div><div class="actions-inline"><?php if($r['signature_path']):?><img class="signature-thumb" src="<?=e($r['signature_path'])?>" alt="TTD"><?php endif;?><a class="btn secondary small" href="employee_form.php?id=<?=$r['id']?>">Ubah &amp; Upload TTD</a></div></div><?php endforeach;?></div><?php page_footer();
